import { createHealpixTopology } from "./healpix.js";

// Earth land/ocean is derived from NOAA NGDC ETOPO1 at 1 degree spacing.
// Earth elevation is sampled from NOAA NGDC ETOPO1 at 1 degree spacing.
// Earth climatology is sampled from WorldClim 2.1 BIO1/BIO2/BIO12 at 1 degree spacing.

const IS_VITE_DEV = Boolean(import.meta.env?.DEV);
const ETOPO1_ELEVATION_URL = new URL("./assets/earth-elevation/etopo1-1deg-int16.bin", import.meta.url).href;
const ETOPO1_WIDTH = 361;
const ETOPO1_HEIGHT = 181;
const WORLDCLIM_CLIMATE_URL = new URL("./assets/earth-climate/worldclim-bio1-bio2-bio12-1deg-int16.bin", import.meta.url).href;
const WORLDCLIM_WIDTH = 361;
const WORLDCLIM_HEIGHT = 181;
const WORLDCLIM_BAND_COUNT = 3;
const WORLDCLIM_NODATA = -32768;
const ROSE_MIN_RAIN_MM = 560;
const ROSE_OPTIMAL_RAIN_MM = 900;
const ROSE_WET_PENALTY_START_MM = 1500;
const ROSE_WET_PENALTY_END_MM = 2100;
const ROSE_ARID_PENALTY_START_MM = 450;
const ROSE_ARID_PENALTY_END_MM = 720;
const BAOBAB_MIN_RAIN_MM = 200;
const BAOBAB_SAVANNA_RAIN_MM = 430;
const BAOBAB_WET_PENALTY_START_MM = 790;
const BAOBAB_WET_PENALTY_END_MM = 1150;
const BAOBAB_HUMID_PENALTY_START_MM = 880;
const BAOBAB_HUMID_PENALTY_END_MM = 1330;
const earthLandFractionPromises = new Map();
let etopo1Elevation = null;
let etopo1ElevationPromise = null;
let worldClimClimate = null;
let worldClimClimatePromise = null;

const EARTH_LAND_FRACTION_BASE64 = Object.freeze({
  "2": "zuKxpQAd66UAzgCcAB1OnAD/AP8AawCUAAAAAADOAJwAAB1rVzEUnBQAAAAxAGuc",
  "4": "uYjO////1v+54kaU/+KcFAAAHQAAABQd/7H//86x/wAAAAAAsf+c/wAAAABj1qUUAAAAAAAxAAAAHevWHU5ruQBGAAD//5z/AAAUAM7/4uIAAAAAAACAYwAAAAAAzrH/AAAAAAAAAAAAADEAAAAAAAAUAAD/xZy5AAAAAE4xa7kARikAAAAAAAAAAJwdALExABRjAAAAazEAAABGzrGxY0YdHQAAAAAAAAAAAAAAAACxHR0AAAAAAB0URrkxHf//",
  "8": "",
  "16": "",
  "32": "",
  "64": ""
});
const decodedLandFractions = new Map();
const decodedLandFractionSources = new Map();

export function earthLandFraction(nside, cellId) {
  const values = landFractionsForNside(nside);
  if (values) {
    return (values[cellId] ?? 0) / 255;
  }

  const fallback = parentLandFractionForUnsupportedNside(nside, cellId);
  return fallback ?? 0;
}

export function earthEffectiveLandFraction(cell, nside) {
  if (cell.__earthEffectiveLandNside === nside && Number.isFinite(cell.__earthEffectiveLandFraction)) {
    return cell.__earthEffectiveLandFraction;
  }
  const value = Math.max(earthLandFraction(nside, cell.id), earthPolarIceLandFractionForCell(cell));
  cell.__earthEffectiveLandNside = nside;
  cell.__earthEffectiveLandFraction = value;
  return value;
}

export function earthPolarIceLandFractionForCell(cell) {
  const lon = earthLongitudeDeg(cell);
  const lat = earthLatitudeDeg(cell);
  return Math.max(antarcticIceLandFraction(lon, lat), greenlandIceLandFraction(lon, lat));
}

function antarcticIceLandFraction(lon, lat) {
  if (lat > -58) {
    return 0;
  }

  const lonRad = (lon * Math.PI) / 180;
  const coastLat =
    -71.5 +
    3.6 * Math.cos(lonRad + 0.2) +
    2.0 * Math.cos(2 * lonRad - 1.1) -
    1.4 * Math.cos(3 * lonRad + 0.7);
  const mainIce = 1 - smoothstep(lat, coastLat, coastLat + 3.2);
  const peninsula =
    geoBlob(lon, lat, -62, -66, 12, 5, 1.0) +
    geoBlob(lon, lat, -66, -69, 8, 4, 0.72);
  const iceShelves =
    geoBlob(lon, lat, -45, -75, 22, 6, 0.38) +
    geoBlob(lon, lat, 170, -76, 30, 6, 0.28);
  return clamp01(Math.max(mainIce, peninsula, iceShelves));
}

function greenlandIceLandFraction(lon, lat) {
  if (lat < 58) {
    return 0;
  }

  return clamp01(
    geoBlob(lon, lat, -42, 73, 18, 10, 1.0) +
      geoBlob(lon, lat, -47, 66, 8, 5, 0.62)
  );
}

export async function preloadEarthLandFractions(nside) {
  const key = String(nside);
  const existing = decodedLandFractions.get(key);
  if (existing && decodedLandFractionSources.get(key) === "etopo1") {
    return existing;
  }

  if (!earthLandFractionPromises.has(key)) {
    earthLandFractionPromises.set(
      key,
      (async () => {
        const elevation = await preloadEarthElevation();
        if (elevation) {
          const values = generateEarthLandFractionsFromElevation(nside);
          decodedLandFractions.set(key, values);
          decodedLandFractionSources.set(key, "etopo1");
          return values;
        }
        return loadEarthLandFractionAsset(nside);
      })()
    );
  }

  return earthLandFractionPromises.get(key);
}

function isLocalHighResolutionLandFraction(nside) {
  return IS_VITE_DEV && (nside === 128 || nside === 256);
}

function earthLandFractionAssetUrl(nside) {
  if (!isLocalHighResolutionLandFraction(nside)) {
    return null;
  }
  const moduleUrl = new URL(import.meta.url);
  moduleUrl.pathname = moduleUrl.pathname.replace(
    /\/[^/]*$/,
    `/assets/earth-land/land-nside${nside}-u8.bin`
  );
  moduleUrl.search = "";
  moduleUrl.hash = "";
  return moduleUrl.href;
}

async function loadEarthLandFractionAsset(nside) {
  const url = earthLandFractionAssetUrl(nside);
  if (!url || typeof fetch !== "function") {
    return null;
  }
  const response = await fetch(url);
  if (!response.ok) {
    throw new Error(`Earth land fraction asset returned ${response.status}`);
  }
  const buffer = await response.arrayBuffer();
  const expectedLength = 12 * nside * nside;
  if (buffer.byteLength !== expectedLength) {
    throw new Error("Earth land fraction asset has an unexpected size.");
  }
  const values = new Uint8Array(buffer);
  decodedLandFractions.set(String(nside), values);
  decodedLandFractionSources.set(String(nside), "asset");
  return values;
}

export function earthLandFractionDataForNside(nside) {
  return landFractionsForNside(nside);
}

export function earthLongitudeDeg(cell) {
  const degrees = (cell.phi * 180) / Math.PI;
  return degrees > 180 ? degrees - 360 : degrees;
}

export function earthLatitudeDeg(cell) {
  return (Math.asin(clamp(cell.height, -1, 1)) * 180) / Math.PI;
}

export async function preloadEarthElevation() {
  if (etopo1Elevation) {
    return etopo1Elevation;
  }

  if (!etopo1ElevationPromise) {
    etopo1ElevationPromise = fetch(ETOPO1_ELEVATION_URL)
      .then((response) => {
        if (!response.ok) {
          throw new Error(`ETOPO1 elevation asset returned ${response.status}`);
        }
        return response.arrayBuffer();
      })
      .then((buffer) => {
        if (buffer.byteLength !== ETOPO1_WIDTH * ETOPO1_HEIGHT * Int16Array.BYTES_PER_ELEMENT) {
          throw new Error("ETOPO1 elevation asset has an unexpected size.");
        }
        etopo1Elevation = new Int16Array(buffer);
        return etopo1Elevation;
      })
      .catch((error) => {
        console.warn("Falling back to analytic Earth elevation.", error);
        return null;
      });
  }

  return etopo1ElevationPromise;
}

export function earthElevationGridData() {
  return etopo1Elevation;
}

export async function preloadEarthClimate() {
  if (worldClimClimate) {
    return worldClimClimate;
  }

  if (!worldClimClimatePromise) {
    worldClimClimatePromise = fetch(WORLDCLIM_CLIMATE_URL)
      .then((response) => {
        if (!response.ok) {
          throw new Error(`WorldClim climate asset returned ${response.status}`);
        }
        return response.arrayBuffer();
      })
      .then((buffer) => {
        if (buffer.byteLength !== WORLDCLIM_WIDTH * WORLDCLIM_HEIGHT * WORLDCLIM_BAND_COUNT * Int16Array.BYTES_PER_ELEMENT) {
          throw new Error("WorldClim climate asset has an unexpected size.");
        }
        worldClimClimate = new Int16Array(buffer);
        return worldClimClimate;
      })
      .catch((error) => {
        console.warn("Falling back to analytic Earth climate.", error);
        return null;
      });
  }

  return worldClimClimatePromise;
}

export function earthClimateGridData() {
  return worldClimClimate;
}

export function earthElevationMetersForCell(cell, nside = 64) {
  if (cell.__earthElevationNside === nside && Number.isFinite(cell.__earthElevationMeters)) {
    return cell.__earthElevationMeters;
  }
  const sampled = sampleEtopo1Elevation(earthLongitudeDeg(cell), earthLatitudeDeg(cell));
  if (sampled !== null) {
    cell.__earthElevationNside = nside;
    cell.__earthElevationMeters = sampled;
    return sampled;
  }

  const value = fallbackEarthElevationMeters(cell, nside);
  cell.__earthElevationNside = nside;
  cell.__earthElevationMeters = value;
  return value;
}

export function earthClimateForCell(cell) {
  if (cell.__earthClimate) {
    return cell.__earthClimate;
  }
  const lon = earthLongitudeDeg(cell);
  const lat = earthLatitudeDeg(cell);
  const sampled = sampleWorldClimClimate(lon, lat);
  if (sampled) {
    cell.__earthClimate = sampled;
    return sampled;
  }

  const value = fallbackEarthClimateForCell(cell);
  cell.__earthClimate = value;
  return value;
}

function sampleEtopo1Elevation(lon, lat) {
  if (!etopo1Elevation) {
    return null;
  }

  const x = modulo(lon + 180, 360);
  const y = clamp(lat + 90, 0, 180);
  const x0 = Math.floor(x);
  const x1 = x0 + 1 > 360 ? 0 : x0 + 1;
  const y0 = Math.floor(y);
  const y1 = Math.min(180, y0 + 1);
  const fx = x - x0;
  const fy = y - y0;
  const v00 = etopo1Elevation[y0 * ETOPO1_WIDTH + x0];
  const v10 = etopo1Elevation[y0 * ETOPO1_WIDTH + x1];
  const v01 = etopo1Elevation[y1 * ETOPO1_WIDTH + x0];
  const v11 = etopo1Elevation[y1 * ETOPO1_WIDTH + x1];
  const south = v00 * (1 - fx) + v10 * fx;
  const north = v01 * (1 - fx) + v11 * fx;
  return south * (1 - fy) + north * fy;
}

function generateEarthLandFractionsFromElevation(nside) {
  const topology = createHealpixTopology(nside);
  const values = new Uint8Array(topology.cells.length);
  for (const cell of topology.cells) {
    const elevationM = sampleEtopo1Elevation(earthLongitudeDeg(cell), earthLatitudeDeg(cell));
    const topoLand = elevationM !== null && elevationM >= 0 ? 1 : 0;
    const iceLand = earthPolarIceLandFractionForCell(cell);
    values[cell.id] = Math.round(clamp01(Math.max(topoLand, iceLand)) * 255);
  }
  return values;
}

function sampleWorldClimClimate(lon, lat) {
  if (!worldClimClimate) {
    return null;
  }

  const x = clamp(lon + 180, 0, 360);
  const y = clamp(lat + 90, 0, 180);
  const meanTempC = sampleWorldClimBand(0, x, y, 10);
  const diurnalRangeC = sampleWorldClimBand(1, x, y, 10);
  const annualPrecipMm = sampleWorldClimBand(2, x, y, 1);
  if (meanTempC === null || diurnalRangeC === null) {
    return null;
  }
  return {
    meanTempC,
    diurnalRangeC,
    annualPrecipMm,
    source: "worldclim"
  };
}

function sampleWorldClimBand(band, x, y, scale) {
  const x0 = Math.floor(x);
  const x1 = Math.min(WORLDCLIM_WIDTH - 1, x0 + 1);
  const y0 = Math.floor(y);
  const y1 = Math.min(WORLDCLIM_HEIGHT - 1, y0 + 1);
  const fx = x - x0;
  const fy = y - y0;
  const offset = band * WORLDCLIM_WIDTH * WORLDCLIM_HEIGHT;
  const samples = [
    { value: worldClimClimate[offset + y0 * WORLDCLIM_WIDTH + x0], weight: (1 - fx) * (1 - fy) },
    { value: worldClimClimate[offset + y0 * WORLDCLIM_WIDTH + x1], weight: fx * (1 - fy) },
    { value: worldClimClimate[offset + y1 * WORLDCLIM_WIDTH + x0], weight: (1 - fx) * fy },
    { value: worldClimClimate[offset + y1 * WORLDCLIM_WIDTH + x1], weight: fx * fy }
  ];
  let weighted = 0;
  let weightTotal = 0;
  for (const sample of samples) {
    if (sample.value === WORLDCLIM_NODATA || sample.weight <= 0) {
      continue;
    }
    weighted += sample.value * sample.weight;
    weightTotal += sample.weight;
  }
  if (weightTotal <= 0) {
    return null;
  }
  return weighted / weightTotal / scale;
}

function fallbackEarthElevationMeters(cell, nside) {
  const land = earthLandFraction(nside, cell.id);
  const lon = earthLongitudeDeg(cell);
  const lat = earthLatitudeDeg(cell);
  if (land < 0.35) {
    const abyss = 3600 + 1800 * Math.exp(-0.5 * ((Math.abs(lat) - 18) / 30) ** 2);
    const ridge =
      geoBlob(lon, lat, -30, 0, 10, 58, 0.38) +
      geoBlob(lon, lat, -112, -35, 9, 38, 0.24) +
      geoBlob(lon, lat, 65, -35, 12, 46, 0.2);
    return -abyss * (1 - ridge);
  }

  const mountain = earthMountainScoreForCell(cell);
  const desert = earthDesertScoreForCell(cell);
  const ice = smoothstep(Math.abs(lat), 62, 86);
  const plateau =
    geoBlob(lon, lat, 86, 31, 24, 9, 3300) +
    geoBlob(lon, lat, -72, -18, 7, 36, 2200) +
    geoBlob(lon, lat, 38, 8, 10, 14, 1200);
  return 120 + mountain * 2100 + desert * 260 + ice * 700 + plateau;
}

function fallbackEarthClimateForCell(cell) {
  const lat = earthLatitudeDeg(cell);
  const absLatitude = Math.abs(lat);
  const latitude01 = absLatitude / 90;
  const meanTempC = clamp(27 - 44 * latitude01 ** 1.35, -34, 32);
  const diurnalRangeC = clamp(8 + earthDesertScoreForCell(cell) * 8 + latitude01 * 3 - earthRainforestScoreForCell(cell) * 4, 3, 18);
  return { meanTempC, diurnalRangeC, source: "analytic" };
}

export function earthMountainScoreForCell(cell) {
  if (Number.isFinite(cell.__earthMountainScore)) {
    return cell.__earthMountainScore;
  }
  const lon = earthLongitudeDeg(cell);
  const lat = earthLatitudeDeg(cell);
  const polarHighland = smoothstep(Math.abs(lat), 68, 82) * 0.22;
  const value = clamp01(
    geoBlob(lon, lat, -72, -18, 7, 34, 1.05) +
      geoBlob(lon, lat, -112, 46, 12, 20, 0.66) +
      geoBlob(lon, lat, 86, 31, 22, 7, 1.05) +
      geoBlob(lon, lat, 44, 39, 18, 8, 0.42) +
      geoBlob(lon, lat, 36, 4, 9, 16, 0.46) +
      geoBlob(lon, lat, 145, -40, 10, 5, 0.38) +
      polarHighland
  );
  cell.__earthMountainScore = value;
  return value;
}

export function earthDesertScoreForCell(cell) {
  if (Number.isFinite(cell.__earthDesertScore)) {
    return cell.__earthDesertScore;
  }
  const lon = earthLongitudeDeg(cell);
  const lat = earthLatitudeDeg(cell);
  const subtropicalDry = Math.exp(-0.5 * ((Math.abs(lat) - 25) / 9) ** 2) * 0.28;
  const value = clamp01(
    subtropicalDry +
      geoBlob(lon, lat, 14, 23, 30, 11, 0.95) +
      geoBlob(lon, lat, 47, 23, 16, 8, 0.74) +
      geoBlob(lon, lat, 90, 42, 24, 8, 0.58) +
      geoBlob(lon, lat, 133, -25, 24, 10, 0.92) +
      geoBlob(lon, lat, -72, -22, 5, 16, 0.72) +
      geoBlob(lon, lat, 20, -25, 14, 10, 0.66) +
      geoBlob(lon, lat, -113, 31, 18, 9, 0.5) +
      geoBlob(lon, lat, -68, -44, 12, 8, 0.36)
  );
  cell.__earthDesertScore = value;
  return value;
}

export function earthRainforestScoreForCell(cell) {
  if (Number.isFinite(cell.__earthRainforestScore)) {
    return cell.__earthRainforestScore;
  }
  const lon = earthLongitudeDeg(cell);
  const lat = earthLatitudeDeg(cell);
  const equatorial = Math.exp(-0.5 * (lat / 12) ** 2);
  const value = clamp01(
    equatorial *
      (geoBlob(lon, lat, -62, -5, 24, 12, 1.0) +
        geoBlob(lon, lat, 22, 0, 19, 11, 0.82) +
        geoBlob(lon, lat, 112, 2, 20, 10, 0.82) +
        geoBlob(lon, lat, 145, -5, 12, 8, 0.58) +
        geoBlob(lon, lat, -84, 9, 12, 7, 0.48))
  );
  cell.__earthRainforestScore = value;
  return value;
}

export function earthAnnualPrecipMmForCell(cell, isLand = false) {
  const cacheKey = isLand ? "__earthAnnualPrecipLandMm" : "__earthAnnualPrecipOceanMm";
  if (Number.isFinite(cell[cacheKey])) {
    return cell[cacheKey];
  }
  const climate = earthClimateForCell(cell);
  if (isLand && climate.source === "worldclim" && Number.isFinite(climate.annualPrecipMm)) {
    const value = Math.max(0, climate.annualPrecipMm);
    cell[cacheKey] = value;
    return value;
  }

  const value = fallbackEarthAnnualPrecipMmForCell(cell, isLand);
  cell[cacheKey] = value;
  return value;
}

export function earthRainClimatologyForCell(cell, isLand = false) {
  return earthAnnualPrecipMmForCell(cell, isLand) / 1000 / 365;
}

function fallbackEarthAnnualPrecipMmForCell(cell, isLand = false) {
  const lon = earthLongitudeDeg(cell);
  const lat = earthLatitudeDeg(cell);
  const absLat = Math.abs(lat);
  const itcz = Math.exp(-0.5 * ((lat - 4) / 10) ** 2);
  const southPacificConvergence = geoBlob(lon, lat, -170, -16, 42, 9, 0.42);
  const stormTracks =
    geoBlob(lon, lat, -35, 50, 42, 10, 0.7) +
    geoBlob(lon, lat, -165, 47, 48, 10, 0.58) +
    geoBlob(lon, lat, 25, 54, 34, 9, 0.38) +
    Math.exp(-0.5 * ((lat + 50) / 10) ** 2) * 0.52;
  const monsoon =
    geoBlob(lon, lat, 78, 21, 18, 10, 0.72) +
    geoBlob(lon, lat, 106, 17, 22, 11, 0.7) +
    geoBlob(lon, lat, 138, -5, 18, 8, 0.48) +
    geoBlob(lon, lat, -80, 7, 13, 8, 0.34);
  const wetContinents = earthRainforestScoreForCell(cell) * 0.88;
  const westCoastWet =
    geoBlob(lon, lat, -124, 48, 7, 12, 0.38) +
    geoBlob(lon, lat, -74, -43, 5, 10, 0.58) +
    geoBlob(lon, lat, 171, -43, 7, 7, 0.42);
  const desert = earthDesertScoreForCell(cell);
  const polarDry = smoothstep(absLat, 62, 83) * 0.34;
  const oceanBoost = isLand ? 0 : 0.28 + 0.2 * stormTracks;
  const continentalDry = isLand ? Math.max(0, desert - 0.18) * 0.7 : 0;

  return clamp(
    210 +
      680 * itcz +
      540 * stormTracks +
      620 * monsoon +
      860 * wetContinents +
      520 * westCoastWet +
      420 * southPacificConvergence +
      360 * oceanBoost -
      520 * continentalDry -
      310 * polarDry,
    isLand ? 35 : 70,
    isLand ? 3600 : 4600
  );
}

export function earthRoseSuitabilityForCell(cell, nside) {
  if (cell.__earthRoseSuitabilityNside === nside && Number.isFinite(cell.__earthRoseSuitability)) {
    return cell.__earthRoseSuitability;
  }
  const land = earthEffectiveLandFraction(cell, nside);
  if (land < 0.35) {
    cell.__earthRoseSuitabilityNside = nside;
    cell.__earthRoseSuitability = 0;
    return 0;
  }

  const lat = earthLatitudeDeg(cell);
  const lon = earthLongitudeDeg(cell);
  const absLat = Math.abs(lat);
  const climate = earthClimateForCell(cell);
  const temperate = Math.exp(-0.5 * ((absLat - 42) / 13) ** 2);
  const mild = Math.exp(-0.5 * ((absLat - 30) / 10) ** 2);
  const northernTemperateRange = smoothstep(lat, 18, 32) * (1 - smoothstep(lat, 58, 70));
  const southernTemperateGardenRange = smoothstep(-lat, 27, 35) * (1 - smoothstep(-lat, 45, 58));
  const nativeRangeAnchors =
    geoBlob(lon, lat, 15, 47, 34, 12, 0.72) +
    geoBlob(lon, lat, 48, 38, 20, 9, 0.56) +
    geoBlob(lon, lat, 78, 41, 20, 9, 0.48) +
    geoBlob(lon, lat, 113, 36, 24, 11, 0.7) +
    geoBlob(lon, lat, 138, 37, 12, 7, 0.48) +
    geoBlob(lon, lat, -96, 42, 34, 13, 0.68) +
    geoBlob(lon, lat, -123, 44, 11, 13, 0.38);
  const settledGardens =
    geoBlob(lon, lat, 8, 48, 18, 8, 0.58) +
    geoBlob(lon, lat, 118, 34, 18, 9, 0.54) +
    geoBlob(lon, lat, 137, 36, 10, 6, 0.44) +
    geoBlob(lon, lat, -82, 38, 18, 9, 0.5) +
    geoBlob(lon, lat, -63, -35, 16, 8, 0.36) +
    geoBlob(lon, lat, 145, -37, 12, 6, 0.34);
  const rainMm = earthAnnualPrecipMmForCell(cell, true);
  const tempFit = smoothstep(climate.meanTempC, -3, 12) * (1 - smoothstep(climate.meanTempC, 24, 31));
  const moistureFit =
    smoothstep(rainMm, ROSE_MIN_RAIN_MM, ROSE_OPTIMAL_RAIN_MM) *
    (1 - smoothstep(rainMm, ROSE_WET_PENALTY_START_MM, ROSE_WET_PENALTY_END_MM));
  const aridExclusion = 0.04 + 0.96 * smoothstep(rainMm, ROSE_ARID_PENALTY_START_MM, ROSE_ARID_PENALTY_END_MM);
  const hotLowlandExclusion =
    1 - 0.88 *
      (1 - smoothstep(absLat, 18, 30)) *
      smoothstep(climate.meanTempC, 22, 28) *
      (1 - 0.55 * smoothstep(earthMountainScoreForCell(cell), 0.34, 0.72));
  const rangeFit = clamp01(
    0.52 * northernTemperateRange +
      0.22 * southernTemperateGardenRange +
      0.34 * nativeRangeAnchors +
      0.24 * settledGardens
  );
  const landscapeFit = clamp01(0.62 * temperate + 0.12 * mild + 0.46 * rangeFit);
  const penalty =
    earthDesertScoreForCell(cell) * 1.06 +
    earthMountainScoreForCell(cell) * 0.42 +
    earthRainforestScoreForCell(cell) * 0.34;
  const value = clamp01(land * landscapeFit * tempFit * (0.14 + 0.86 * moistureFit) * aridExclusion * hotLowlandExclusion * (1 - clamp01(penalty)));
  cell.__earthRoseSuitabilityNside = nside;
  cell.__earthRoseSuitability = value;
  return value;
}

export function earthBaobabSuitabilityForCell(cell, nside) {
  if (cell.__earthBaobabSuitabilityNside === nside && Number.isFinite(cell.__earthBaobabSuitability)) {
    return cell.__earthBaobabSuitability;
  }
  const land = earthEffectiveLandFraction(cell, nside);
  if (land < 0.35) {
    cell.__earthBaobabSuitabilityNside = nside;
    cell.__earthBaobabSuitability = 0;
    return 0;
  }

  const lon = earthLongitudeDeg(cell);
  const lat = earthLatitudeDeg(cell);
  const climate = earthClimateForCell(cell);
  const tropicalDry = Math.exp(-0.5 * ((Math.abs(lat) - 13) / 12) ** 2);
  const nativeRange =
    geoBlob(lon, lat, 20, 8, 22, 15, 1.0) +
    geoBlob(lon, lat, 29, -15, 15, 12, 0.82) +
    geoBlob(lon, lat, 47, -20, 7, 9, 0.72) +
    geoBlob(lon, lat, 132, -17, 22, 10, 0.38);
  const rainMm = earthAnnualPrecipMmForCell(cell, true);
  const warmFit = smoothstep(climate.meanTempC, 16, 24) * (1 - smoothstep(climate.meanTempC, 34, 41));
  const savannaRain =
    smoothstep(rainMm, BAOBAB_MIN_RAIN_MM, BAOBAB_SAVANNA_RAIN_MM) *
    (1 - smoothstep(rainMm, BAOBAB_WET_PENALTY_START_MM, BAOBAB_WET_PENALTY_END_MM));
  const drySeasonFit = clamp01(0.42 + earthDesertScoreForCell(cell) * 0.42 + tropicalDry * 0.26);
  const rangeFit = clamp01(0.62 * nativeRange + 0.28 * tropicalDry + 0.12 * drySeasonFit);
  const penalty =
    earthRainforestScoreForCell(cell) * 1.02 +
    earthMountainScoreForCell(cell) * 0.7 +
    Math.max(0, earthDesertScoreForCell(cell) - 0.84) * 0.62 +
    smoothstep(rainMm, BAOBAB_HUMID_PENALTY_START_MM, BAOBAB_HUMID_PENALTY_END_MM) * 0.48;
  const value = clamp01(land * rangeFit * warmFit * savannaRain * drySeasonFit * (1 - clamp01(penalty)));
  cell.__earthBaobabSuitabilityNside = nside;
  cell.__earthBaobabSuitability = value;
  return value;
}

export function earthKoppenClassForCell(cell, nside) {
  if (cell.__earthKoppenNside === nside && cell.__earthKoppenClass) {
    return cell.__earthKoppenClass;
  }
  const cacheKoppen = (value) => {
    cell.__earthKoppenNside = nside;
    cell.__earthKoppenClass = value;
    return value;
  };
  const land = earthEffectiveLandFraction(cell, nside);
  if (land < 0.35) {
    return cacheKoppen("Ocean");
  }

  const climate = earthClimateForCell(cell);
  const meanTempC = climate.meanTempC;
  const rainMm = earthAnnualPrecipMmForCell(cell, true);
  const absLat = Math.abs(earthLatitudeDeg(cell));
  const desert = earthDesertScoreForCell(cell);
  const rainforest = earthRainforestScoreForCell(cell);
  const elevation = earthElevationMetersForCell(cell, nside);
  const coldPenalty = Math.max(0, elevation - 1800) / 1800;
  const effectiveTempC = meanTempC - coldPenalty * 4.5;

  if (absLat > 72 || effectiveTempC < -4) {
    return cacheKoppen(effectiveTempC < -10 || absLat > 78 ? "EF" : "ET");
  }

  const dryThresholdMm = clamp(20 * Math.max(0, effectiveTempC) + 140 + desert * 120, 160, 780);
  if (rainMm < dryThresholdMm) {
    const arid = rainMm < dryThresholdMm * 0.5;
    const hot = effectiveTempC >= 18;
    if (arid) {
      return cacheKoppen(hot ? "BWh" : "BWk");
    }
    return cacheKoppen(hot ? "BSh" : "BSk");
  }

  if (effectiveTempC >= 18) {
    if (rainforest > 0.42 && rainMm >= 1800) {
      return cacheKoppen("Af");
    }
    if (rainMm >= 1150) {
      return cacheKoppen("Am");
    }
    return cacheKoppen("Aw");
  }

  if (effectiveTempC >= -3) {
    const mediterranean =
      absLat >= 28 &&
      absLat <= 46 &&
      rainMm < 900 &&
      desert > 0.12;
    if (mediterranean) {
      return cacheKoppen(effectiveTempC >= 14 ? "Csa" : "Csb");
    }
    if (effectiveTempC >= 14 && rainMm >= 760) {
      return cacheKoppen("Cfa");
    }
    return cacheKoppen("Cfb");
  }

  if (effectiveTempC >= 6) {
    return cacheKoppen("Dfa");
  }
  if (effectiveTempC >= -1) {
    return cacheKoppen("Dfb");
  }
  return cacheKoppen("Dfc");
}

function landFractionsForNside(nside) {
  const key = String(nside);
  if (decodedLandFractions.has(key)) {
    return decodedLandFractions.get(key);
  }

  const base64 = EARTH_LAND_FRACTION_BASE64[key];
  if (!base64) {
    return null;
  }

  const binary = globalThis.atob(base64);
  const values = new Uint8Array(binary.length);
  for (let index = 0; index < binary.length; index += 1) {
    values[index] = binary.charCodeAt(index);
  }
  decodedLandFractions.set(key, values);
  decodedLandFractionSources.set(key, "legacy");
  return values;
}

function parentLandFractionForUnsupportedNside(nside, cellId) {
  const parentNside = availableParentLandNside(nside);
  if (!parentNside) {
    return null;
  }

  const parentValues = landFractionsForNside(parentNside);
  if (!parentValues) {
    return null;
  }

  const parentId = nestedParentCellId(nside, cellId, parentNside);
  return parentId === null ? null : (parentValues[parentId] ?? 0) / 255;
}

function availableParentLandNside(nside) {
  const requested = Number(nside);
  if (!Number.isInteger(requested) || requested <= 0) {
    return null;
  }

  const available = Object.keys(EARTH_LAND_FRACTION_BASE64)
    .map(Number)
    .filter((candidate) => candidate < requested && requested % candidate === 0)
    .sort((a, b) => b - a);
  return available[0] ?? null;
}

function nestedParentCellId(nside, cellId, parentNside) {
  const childNside = Number(nside);
  const parent = Number(parentNside);
  const id = Number(cellId);
  if (
    !Number.isInteger(childNside) ||
    !Number.isInteger(parent) ||
    !Number.isInteger(id) ||
    childNside <= parent ||
    childNside % parent !== 0
  ) {
    return null;
  }

  const childFaceSize = childNside * childNside;
  const parentFaceSize = parent * parent;
  const face = Math.floor(id / childFaceSize);
  if (face < 0 || face >= 12) {
    return null;
  }

  const ratio = childNside / parent;
  const shiftBits = Math.round(Math.log2(ratio));
  if (2 ** shiftBits !== ratio) {
    return null;
  }

  const childLocalId = id - face * childFaceSize;
  return face * parentFaceSize + (childLocalId >> (2 * shiftBits));
}

function geoBlob(lon, lat, centerLon, centerLat, lonScale, latScale, amplitude) {
  const dx = signedLonDelta(lon, centerLon);
  const dy = lat - centerLat;
  return amplitude * Math.exp(-0.5 * ((dx / lonScale) ** 2 + (dy / latScale) ** 2));
}

function signedLonDelta(a, b) {
  let delta = a - b;
  while (delta <= -180) delta += 360;
  while (delta > 180) delta -= 360;
  return delta;
}

function modulo(value, period) {
  return ((value % period) + period) % period;
}

function smoothstep(value, edge0, edge1) {
  const t = clamp((value - edge0) / (edge1 - edge0 || 1), 0, 1);
  return t * t * (3 - 2 * t);
}

function clamp01(value) {
  return clamp(value, 0, 1);
}

function clamp(value, min, max) {
  return Math.min(max, Math.max(min, value));
}
